import heapq

# === Top-K Largest Elements — O(N log K) ===
def top_k_largest(nums, k):
    heap = nums[:k]
    heapq.heapify(heap)         # min-heap of size K
    for num in nums[k:]:
        if num > heap[0]:       # larger than current minimum
            heapq.heapreplace(heap, num)  # faster than pop+push
    return sorted(heap, reverse=True)

# === Kth Largest Element — O(N log K) ===
def kth_largest(nums, k):
    return heapq.nlargest(k, nums)[-1]  # O(N log K)
    # Or: maintain min-heap of size K (same complexity, same idea)

# === K-Way Merge — O(N log K) ===
def merge_k_sorted(arrays):
    result = []
    # heap stores (value, array_index, element_index)
    heap = []
    for i, arr in enumerate(arrays):
        if arr:
            heapq.heappush(heap, (arr[0], i, 0))

    while heap:
        val, arr_i, elem_i = heapq.heappop(heap)
        result.append(val)
        if elem_i + 1 < len(arrays[arr_i]):
            next_val = arrays[arr_i][elem_i + 1]
            heapq.heappush(heap, (next_val, arr_i, elem_i + 1))
    return result

# Example
arrs = [[1, 4, 7], [2, 5, 8], [3, 6, 9]]
print(merge_k_sorted(arrs))  # [1,2,3,4,5,6,7,8,9]

import heapq

class MedianFinder:
    def __init__(self):
        self.lo = []   # max-heap (lower half) — negate for max-heap
        self.hi = []   # min-heap (upper half)

    def add_num(self, num: int) -> None:
        # Always push to lo first
        heapq.heappush(self.lo, -num)

        # Maintain max(lo) <= min(hi)
        if self.hi and -self.lo[0] > self.hi[0]:
            heapq.heappush(self.hi, -heapq.heappop(self.lo))

        # Rebalance sizes: lo can have at most 1 more element
        if len(self.lo) > len(self.hi) + 1:
            heapq.heappush(self.hi, -heapq.heappop(self.lo))
        elif len(self.hi) > len(self.lo):
            heapq.heappush(self.lo, -heapq.heappop(self.hi))

    def find_median(self) -> float:
        if len(self.lo) > len(self.hi):
            return -self.lo[0]          # odd total → lo has one extra
        return (-self.lo[0] + self.hi[0]) / 2.0  # even total → average tops

mf = MedianFinder()
for n in [1, 2, 3, 4, 5]:
    mf.add_num(n)
    print(mf.find_median())  # 1.0, 1.5, 2.0, 2.5, 3.0

import heapq
from collections import defaultdict

def dijkstra(graph, src):
    """
    graph: {node: [(weight, neighbor), ...]}
    Returns: dist dict — shortest distance from src to every node
    """
    dist = defaultdict(lambda: float('inf'))
    dist[src] = 0
    heap = [(0, src)]   # (distance, node)

    while heap:
        d, u = heapq.heappop(heap)
        if d > dist[u]:
            continue    # stale entry — skip (lazy deletion)
        for weight, v in graph[u]:
            if dist[u] + weight < dist[v]:
                dist[v] = dist[u] + weight
                heapq.heappush(heap, (dist[v], v))
    return dict(dist)

# Example: weighted graph
graph = {
    'A': [(1, 'B'), (4, 'C')],
    'B': [(1, 'A'), (2, 'C'), (5, 'D')],
    'C': [(4, 'A'), (2, 'B'), (1, 'D')],
    'D': [(5, 'B'), (1, 'C')]
}
print(dijkstra(graph, 'A'))  # {'A': 0, 'B': 1, 'C': 3, 'D': 4}
